const searches = [{"query": "AI Operations", "aroundQuery": "Europe"}, {"query": "AI Project Manager", "aroundQuery": "Europe"}, {"query": "AI Customer Success", "aroundQuery": "Europe"}, {"query": "AI Strategy", "aroundQuery": "Europe"}, {"query": "Customer Success", "aroundQuery": "Europe"}, {"query": "Operations Manager", "aroundQuery": "Netherlands"}];
return searches.map(s => ({
  json: {
    url: `https://api.welcometothejungle.com/api/v1/jobs?query=${encodeURIComponent(s.query)}&around_query=${encodeURIComponent(s.aroundQuery)}&contract_type=full_time&page=1&per_page=20`,
    source_platform: 'wttj'
  }
}));

const response = $input.first().json;
const jobs = response.jobs || response.data || response.results || [];

return jobs.map(job => ({
  json: {
    job_id: job.slug || job.id || '',
    job_title: job.name || job.title || '',
    company: (job.organization && job.organization.name) || job.company || '',
    location: (job.office && job.office.city) || job.location || 'Europe',
    job_url: job.url || `https://www.welcometothejungle.com/jobs/${job.slug}`,
    description: (job.description || job.profile || '').replace(/<[^>]+>/g, ' ').trim().substring(0, 3000),
    source_platform: 'wttj'
  }
}));

const fs = require('fs');
const path = require('path');

const cacheDir = 'C:/Users/Dev/Desktop/Job Agents/job-agent/setup/cache';
if (!fs.existsSync(cacheDir)) fs.mkdirSync(cacheDir, { recursive: true });

// Per-platform cache file
const item = $input.first().json;
const platform = item.source_platform || 'unknown';
const cacheFile = path.join(cacheDir, `seen_${platform.replace(/[^a-z0-9_]/gi, '_')}.json`);

let seen = [];
try { seen = JSON.parse(fs.readFileSync(cacheFile, 'utf-8')); } catch (e) {}

const url = item.job_url || item.job_id || '';
if (!url) return [];
if (seen.includes(url)) return []; // Already seen

seen.push(url);
if (seen.length > 5000) seen = seen.slice(-3000);
fs.writeFileSync(cacheFile, JSON.stringify(seen));

return [{ json: item }];
